77	/// Validate an ochid trailer value against expected prefix, length, and other repo.
78	pub fn validate_ochid(
79	    value: &str,
80	    other_prefix: &str,
81	    id_len: usize,
82	    other_workspace: &Workspace,
83	    other_repo: &Arc<ReadonlyRepo>,
84	) -> OchidIssues {
85	    // Extract the actual prefix (everything before the bare ID)
86	    let bare_id = extract_bare_id(value);
87	    let actual_prefix = &value[..value.len() - bare_id.len()];
88	
89	    let wrong_prefix = if actual_prefix != other_prefix {
90	        Some((actual_prefix.to_string(), other_prefix.to_string()))
91	    } else {
92	        None
93	    };
94	
95	    let wrong_length = if bare_id.len() != id_len {
96	        Some((bare_id.len(), id_len))
97	    } else {
98	        None
99	    };
100	
101	    // Check if the ID resolves in the other repo
102	    let not_found = common::resolve_revset(other_workspace, other_repo, bare_id)
103	        .map(|ids| ids.is_empty())
104	        .unwrap_or(true); // OK: resolve failure → treat as not found
105	
106	    OchidIssues {
107	        wrong_prefix,
108	        wrong_length,
109	        not_found,
110	        bare_id: bare_id.to_string(),
111	    }
