192	/// Fix the ochid trailer in a commit description.
193	///
194	/// If `resolved_id` is provided, it replaces the bare changeID entirely
195	/// (used when the existing ID is too short to extend by truncation alone).
196	pub fn fix_ochid_in_description(
197	    desc: &str,
198	    other_prefix: &str,
199	    id_len: usize,
200	    new_title: Option<&str>,
201	    resolved_id: Option<&str>,
202	) -> String {
203	    let mut lines: Vec<String> = desc.lines().map(|l| l.to_string()).collect();
204	
205	    // Fix title if requested
206	    if let Some(title) = new_title
207	        && !lines.is_empty()
208	    {
209	        lines[0] = title.to_string();
210	    }
211	
212	    // Fix ochid trailer
213	    for line in &mut lines {
214	        let trimmed = line.trim();
215	        if let Some(value) = trimmed.strip_prefix("ochid:") {
216	            let value = value.trim();
217	            let id = if let Some(rid) = resolved_id {
218	                &rid[..rid.len().min(id_len)]
219	            } else {
220	                let bare_id = extract_bare_id(value);
221	                &bare_id[..bare_id.len().min(id_len)]
222	            };
223	            *line = format!("ochid: {other_prefix}{id}");
224	        }
225	    }
226	
227	    // Preserve trailing newline if original had one
228	    let mut result = lines.join("\n");
229	    if desc.ends_with('\n') {
230	        result.push('\n');
231	    }
232	    result
233	}
