235	/// Append an ochid trailer to a commit description.
236	pub fn append_ochid_trailer(
237	    desc: &str,
238	    other_prefix: &str,
239	    change_id: &str,
240	    id_len: usize,
241	) -> String {
242	    let short_id = &change_id[..change_id.len().min(id_len)];
243	    let trailer = format!("ochid: {other_prefix}{short_id}");
244	
245	    let mut result = desc.trim_end().to_string();
246	    // Add blank line before trailer if body exists, otherwise just newline
247	    if result.lines().count() > 1 {
248	        result.push('\n');
249	    } else {
250	        result.push_str("\n\n");
251	    }
252	    result.push_str(&trailer);
253	    result.push('\n');
254	    result
255	}
