    #[test]
    fn truncate_long_id() {
        let desc = "Title\n\nochid: abcdefghijklmnop\n";
        let result = fix_ochid_in_description(desc, "/", DEFAULT_ID_LEN, None, None);
        assert!(result.contains("ochid: /abcdefghijkl"));
        assert!(!result.contains("mnop"));
    }

    #[test]
    fn fix_title_and_ochid() {
        let desc = "Old title\n\nochid: bare12345678\n";
        let result =
            fix_ochid_in_description(desc, "/.claude/", DEFAULT_ID_LEN, Some("New title"), None);
        assert!(result.starts_with("New title\n"));
        assert!(result.contains("ochid: /.claude/bare12345678"));
    }

    #[test]
    fn no_ochid_no_change() {
        let desc = "Title\n\nNo trailer here.\n";
        let result = fix_ochid_in_description(desc, "/.claude/", DEFAULT_ID_LEN, None, None);
        assert_eq!(result, desc);
    }

    #[test]
    fn other_path_without_trailing_slash() {
        let desc = "Title\n\nochid: abcdefghijkl\n";
        let result = fix_ochid_in_description(desc, "/", DEFAULT_ID_LEN, None, None);
        assert!(result.contains("ochid: /abcdefghijkl"));
    }

    #[test]
    fn custom_id_len() {
        let desc = "Title\n\nochid: abcdefghijklmnop\n";
        let result = fix_ochid_in_description(desc, "/", 8, None, None);
        assert!(result.contains("ochid: /abcdefgh"));
        assert!(!result.contains("ijkl"));
    }

    #[test]
    fn extend_short_id_with_resolved() {
        let desc = "Title\n\nochid: /abcdefgh\n";
        let result =
            fix_ochid_in_description(desc, "/", DEFAULT_ID_LEN, None, Some("abcdefghijkl"));
        assert!(result.contains("ochid: /abcdefghijkl"));
    }

    #[test]
    fn resolved_id_with_prefix_fix() {
        let desc = "Title\n\nochid: /wrong/abcdefgh\n";
        let result = fix_ochid_in_description(
            desc,
            "/.claude/",
            DEFAULT_ID_LEN,
            None,
            Some("abcdefghijklmnop"),
        );
        assert!(result.contains("ochid: /.claude/abcdefghijkl"));
    }

    #[test]
    fn append_ochid_title_only() {
        let desc = "Title\n";
        let result = append_ochid_trailer(desc, "/.claude/", "abcdefghijklmnop", DEFAULT_ID_LEN);
        assert_eq!(result, "Title\n\nochid: /.claude/abcdefghijkl\n");
    }

    #[test]
    fn append_ochid_with_body() {
        let desc = "Title\n\nSome body text.\n";
        let result = append_ochid_trailer(desc, "/", "abcdefghijklmnop", DEFAULT_ID_LEN);
        assert_eq!(result, "Title\n\nSome body text.\nochid: /abcdefghijkl\n");
    }

    #[test]
    fn append_ochid_root_prefix() {
        let desc = "Title\n";
        let result = append_ochid_trailer(desc, "/", "xyzxyzxyzxyz", DEFAULT_ID_LEN);
        assert_eq!(result, "Title\n\nochid: /xyzxyzxyzxyz\n");
    }

    #[test]
    fn extract_bare_id_with_prefix() {
        assert_eq!(extract_bare_id("/.claude/abcdefghijkl"), "abcdefghijkl");
    }

    #[test]
    fn extract_bare_id_root_prefix() {
        assert_eq!(extract_bare_id("/abcdefghijkl"), "abcdefghijkl");
    }

    #[test]
    fn extract_bare_id_no_prefix() {
        assert_eq!(extract_bare_id("abcdefghijkl"), "abcdefghijkl");
    }

    #[test]
    fn extract_ochid_from_desc_found() {
        let desc = "Title\n\nBody.\n\nochid: /.claude/abcdefghijkl\n";
        assert_eq!(
            extract_ochid_from_desc(desc),
            Some("/.claude/abcdefghijkl".to_string())
        );
    }

    #[test]
    fn extract_ochid_from_desc_missing() {
        let desc = "Title\n\nNo trailer.\n";
        assert_eq!(extract_ochid_from_desc(desc), None);
    }
}

pub struct StateLayout {
    /// Full path `<repo>/<state-dir>/<state-file>`.
    pub path: PathBuf,
}

/// Read `state_dir` / `state_file` from `<repo_root>/.vc-config.toml`
/// under the `[push]` section, falling back to defaults (`.vc-x1`
/// and `push-state.toml`).
///
/// Missing config file is not an error — every workspace has the
/// defaults applied silently so `vc-x1 push --status` works on a
/// fresh clone without ceremony.
pub fn resolve_state_layout(repo_root: &Path) -> StateLayout {
    let config_path = repo_root.join(".vc-config.toml");
    let (dir, file) = if config_path.exists() {
        match toml_load(&config_path) {
            Ok(map) => {
                let dir = map
                    .get("push.state-dir")
                    .cloned()
                    .unwrap_or_else(|| DEFAULT_STATE_DIR.to_string());
                let file = map
                    .get("push.state-file")
                    .cloned()
                    .unwrap_or_else(|| DEFAULT_STATE_FILE.to_string());
                (dir, file)
            }
            Err(e) => {
                debug!("push: ignoring unparseable .vc-config.toml: {e}");
                (
                    DEFAULT_STATE_DIR.to_string(),
                    DEFAULT_STATE_FILE.to_string(),
                )
            }
        }
    } else {
        (
            DEFAULT_STATE_DIR.to_string(),
            DEFAULT_STATE_FILE.to_string(),
        )
    };
    let path = repo_root.join(&dir).join(&file);
    StateLayout { path }
}

/// Persistent state for an in-progress `push` run.
///
/// Serialized as flat TOML (`key = "value"`) under the dir/file
/// configured in `.vc-config.toml`'s `[push]` section. Fields added
/// across dev steps are all `Option<_>` so older states remain
/// loadable — only `version` / `stage` / `bookmark` / `started_at`
/// are required. See the module docstring for which dev step
/// introduced which field.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PushState {
    /// State-file format version; must match `STATE_FORMAT_VERSION`
    /// to be considered readable.
    pub version: u32,
    /// The next stage to execute on resume.
    pub stage: Stage,
    /// Bookmark being advanced by this run (persisted so resume
    /// doesn't need `--bookmark` again).
    pub bookmark: String,
    /// ISO-8601 UTC timestamp captured when the state was first
    /// written. Informational — helps the user spot stale state.
    pub started_at: String,
    /// App-repo changeID captured at `message` stage (before
    /// `commit-app` runs). Stable across `jj commit` — becomes the
    /// chid of the just-committed change. Used when composing the
    /// `.claude` commit's ochid trailer. Added in 0.37.0-2.
    pub app_chid: Option<String>,
    /// `.claude` repo changeID used by the app-repo commit's ochid
    /// trailer. Either the pre-commit `@` chid (when `.claude` has
    /// pending changes — becomes `@-` after commit) or the current
    /// `@-` chid (when `.claude` is clean — stays stable). Added in
    /// 0.37.0-2.
    pub claude_chid: Option<String>,
    /// Whether `.claude`'s working copy had changes at `message`
    /// time. Decides whether `commit-claude` actually runs or
    /// skips. Added in 0.37.0-2.
    pub claude_had_changes: Option<bool>,
    /// `jj op` id of the app repo captured before `commit-app`. On
    /// failure in stages 4-6, `jj op restore` rewinds here. Added
    /// in 0.37.0-2.
    pub op_app: Option<String>,
    /// `jj op` id of `.claude` captured before `commit-app`. Same
    /// rollback target as `op_app`. Added in 0.37.0-2.
    pub op_claude: Option<String>,
    /// Composed commit title — persisted so resume doesn't need
    /// `--title` re-passed. Set during `message` stage from either

