        let sel = RepoSelector {
            category: "local".into(),
            value: None,
        };
        let (cat, val) = resolve_repo(&cfg, Some("work"), Some(&sel)).unwrap();
        assert_eq!(cat, "local");
        assert_eq!(val, "/work/fixtures");
