pub fn load_from(path: &Path) -> Result<UserConfig, Box<dyn std::error::Error>> {
    if !path.exists() {
        return Ok(UserConfig::default());
    }
    let map = toml_simple::toml_load(path)?;

    let mut cfg = UserConfig {
        default_account: map.get("default.account").cloned(),
        default_debug: map.get("default.debug").cloned(),
        accounts: HashMap::new(),
    };

    // Walk all keys looking for `account.<name>.…` patterns and
    // group into per-account `AccountConfig` entries.
    for (full_key, value) in &map {
        let Some(rest) = full_key.strip_prefix("account.") else {
            continue;
        };
        // rest is `<name>.<...>`; split at the first dot.
        let Some((name, suffix)) = rest.split_once('.') else {
            continue;
        };
        let account = cfg
            .accounts
            .entry(name.to_string())
            .or_insert_with(AccountConfig::default);
        match suffix {
            "repo.default" => {
                account.repo_default = Some(value.clone());
            }
            s if let Some(cat) = s.strip_prefix("repo.category.") => {
                account.repo_category.insert(cat.to_string(), value.clone());
            }
            _ => {} // unknown sub-key; ignore
        }
    }

    Ok(cfg)
}

